/*
  Rebirth Online News Framework Styles
  ------------------------------------
  The CSS below recreates the clean, cinematic layout from the design.
*/

:root {
  /* Core palette */
  --color-primary-light: #ffffff;
  --color-primary-dark: #111111;

  --color-secondary-light: #e5e5e5;
  --color-secondary-muted: #777777;

  --color-neutral-50: #f7f7f7;
  --color-neutral-200: #cccccc;
  --color-neutral-400: #999999;

  --color-accent-gold: #cbb58a;

  --color-success: #3cb371;
  --color-error: #e74c3c;
  --color-warning: #f1c40f;
  --color-info: #3498db;

  --color-border-subtle: #e5e5e5;

  /* Typography */
  --font-heading: "Space Grotesk", Helvetica, sans-serif;
  --font-body: "Source Sans 3", Arial, sans-serif;
  --font-code: "Source Code Pro", monospace;

  --font-size-h1: 32px;
  --font-size-h2: 24px;
  --font-size-h3: 18px;
  --font-size-body: 14px;
  --font-size-small: 12px;

  --font-weight-light: 300;
  --font-weight-regular: 400;
  --font-weight-medium: 500;
  --font-weight-semibold: 600;
  --font-weight-bold: 700;

  --line-height-tight: 1.2;
  --line-height-normal: 1.5;
  --line-height-relaxed: 1.75;

  /* Spacing scale (4px base, built around 8px rhythm) */
  --space-0-5: 4px;
  --space-1: 8px;
  --space-2: 16px;
  --space-3: 24px;
  --space-4: 32px;
  --space-5: 48px;
  --space-6: 64px;

  /* Layout */
  --site-max-width: 1040px;
  --site-gutter: 24px;

  --radius-sm: 4px;

  --border-thin: 1px solid var(--color-border-subtle);
}

/* Global reset / base ---------------------------------------------------- */

*,
*::before,
*::after {
  box-sizing: border-box;
}

html,
body {
  margin: 0;
  padding: 0;
}

body.site {
  min-height: 100vh;
  background-color: var(--color-primary-light);
  color: var(--color-primary-dark);
  font-family: var(--font-body);
  font-size: var(--font-size-body);
  line-height: var(--line-height-normal);
  -webkit-font-smoothing: antialiased;
}

img {
  max-width: 100%;
  height: auto;
  display: block;
}

a {
  color: inherit;
  text-decoration: none;
}

a:focus {
  outline: 2px solid var(--color-accent-gold);
  outline-offset: 2px;
}

ul,
ol {
  margin: 0;
  padding: 0;
  list-style: none;
}

.container {
  max-width: var(--site-max-width);
  margin-left: auto;
  margin-right: auto;
  padding-left: var(--site-gutter);
  padding-right: var(--site-gutter);
}

/* Header and hero -------------------------------------------------------- */

.site-header {
  position: relative;
}

.hero-banner {
  position: relative;
  color: var(--color-primary-light);
  background-color: #151515; /* fallback behind hero image */
  background-image: url("assets/hero-banner.jpg");
  background-size: cover;
  background-position: center center;
  background-repeat: no-repeat;
  min-height: 220px;
}

.hero-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(
    to bottom,
    rgba(0, 0, 0, 0.7) 0%,
    rgba(0, 0, 0, 0.35) 45%,
    rgba(0, 0, 0, 0.78) 100%
  );
}

.hero-inner {
  position: relative;
  padding-top: var(--space-3);
  padding-bottom: var(--space-4);
}

.hero-top {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  column-gap: var(--space-2);
}

.site-logo {
  text-decoration: none;
}

.logo-text {
  font-family: var(--font-heading);
  font-weight: var(--font-weight-bold);
  letter-spacing: 0.18em;
  text-transform: uppercase;
  font-size: 26px;
  color: var(--color-primary-light);
  white-space: nowrap;
}

.hero-meta {
  display: flex;
  align-items: center;
}

.hero-lang {
  font-family: var(--font-body);
  font-size: 12px;
  letter-spacing: 0.15em;
  text-transform: uppercase;
  color: rgba(255, 255, 255, 0.75);
}

.hero-lang-divider {
  margin: 0 6px;
  color: rgba(255, 255, 255, 0.55);
}

/* Primary navigation (inside hero) -------------------------------------- */

.primary-nav {
  margin-top: var(--space-4);
}

.primary-nav-list {
  display: flex;
  flex-wrap: wrap;
  row-gap: var(--space-1);
  column-gap: var(--space-3);
}

.primary-nav-item {
  display: flex;
}

.primary-nav-link {
  position: relative;
  padding-bottom: 6px;
  font-family: var(--font-body);
  font-size: 14px;
  font-weight: var(--font-weight-regular);
  letter-spacing: 0.04em;
  color: rgba(255, 255, 255, 0.82);
  text-transform: none;
  transition: color 150ms ease-out, border-color 150ms ease-out;
}

.primary-nav-link::after {
  content: "";
  position: absolute;
  left: 0;
  bottom: 0;
  width: 100%;
  height: 2px;
  background-color: transparent;
  transition: background-color 150ms ease-out;
}

.primary-nav-link:hover {
  color: var(--color-primary-light);
}

.primary-nav-link:hover::after {
  background-color: rgba(255, 255, 255, 0.7);
}

.primary-nav-link.is-active {
  font-weight: var(--font-weight-medium);
  color: var(--color-primary-light);
}

.primary-nav-link.is-active::after {
  background-color: var(--color-accent-gold);
}

/* Main content wrapper --------------------------------------------------- */

.site-main {
  padding-top: var(--space-5);
  padding-bottom: var(--space-5);
}

/* Footer ----------------------------------------------------------------- */

.site-footer {
  border-top: var(--border-thin);
  background-color: var(--color-neutral-50);
}

.footer-inner {
  padding-top: var(--space-3);
  padding-bottom: var(--space-3);
  display: flex;
  flex-wrap: wrap;
  align-items: center;
  justify-content: space-between;
  gap: var(--space-2);
}

.footer-nav-list {
  display: flex;
  flex-wrap: wrap;
  column-gap: var(--space-3);
  row-gap: var(--space-1);
}

.footer-nav-link {
  font-size: var(--font-size-small);
  color: var(--color-neutral-400);
  text-decoration: none;
  transition: color 150ms ease-out;
}

.footer-nav-link:hover {
  color: var(--color-primary-dark);
}

.footer-meta {
  margin: 0;
  font-size: var(--font-size-small);
  color: var(--color-neutral-400);
  text-align: right;
}

/* Typography utilities --------------------------------------------------- */

h1,
.h1 {
  font-family: var(--font-heading);
  font-size: var(--font-size-h1);
  font-weight: var(--font-weight-semibold);
  line-height: var(--line-height-tight);
  margin: 0 0 var(--space-2);
}

h2,
.h2 {
  font-family: var(--font-heading);
  font-size: var(--font-size-h2);
  font-weight: var(--font-weight-medium);
  line-height: var(--line-height-tight);
  margin: 0 0 var(--space-2);
}

h3,
.h3 {
  font-family: var(--font-heading);
  font-size: var(--font-size-h3);
  font-weight: var(--font-weight-medium);
  line-height: var(--line-height-tight);
  margin: 0 0 var(--space-1);
}

p {
  margin-top: 0;
  margin-bottom: var(--space-2);
}

small,
.small {
  font-size: var(--font-size-small);
}

.text-muted {
  color: var(--color-neutral-400);
}

/* Responsive adjustments ------------------------------------------------- */

@media (max-width: 768px) {
  .hero-inner {
    padding-top: var(--space-2);
    padding-bottom: var(--space-3);
  }

  .logo-text {
    font-size: 22px;
  }

  .primary-nav-list {
    column-gap: var(--space-2);
  }

  .site-main {
    padding-top: var(--space-4);
    padding-bottom: var(--space-4);
  }

  .footer-inner {
    flex-direction: column;
    align-items: flex-start;
  }

  .footer-meta {
    text-align: left;
  }
}

@media (max-width: 480px) {
  .hero-top {
    flex-direction: column;
    row-gap: var(--space-1);
  }

  .hero-meta {
    align-self: flex-end;
  }
}
